using Asp.Versioning;using Fixar.API.Security;using Fixar.Application.Common.Interfaces;using Fixar.Application.Common.Models;using Fixar.Domain.Entities;using Fixar.Infrastructure.Identity;using Fixar.Infrastructure.Persistence;using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;
namespace Fixar.API.Controllers;
#pragma warning disable CS8604
[ApiController,ApiVersion("1.0"),Route("api/v{version:apiVersion}/maintenance-checklists"),Authorize(Policy=AuthorizationPolicies.CanViewMaintenance)]public class MaintenanceChecklistsController(ApplicationDbContext db,ICurrentUserService user):ControllerBase{
[HttpGet("templates")]public async Task<IActionResult>Templates(CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.MaintenanceChecklistTemplates.AsNoTracking().Select(x=>new{x.Id,x.Name,x.AssetType,x.WorkType,x.Description,x.IsActive,Items=x.Items.OrderBy(i=>i.Sequence).Select(i=>new{i.Id,i.Sequence,i.ItemText,i.ItemType,i.IsRequired,i.ExpectedValue,i.MinimumValue,i.MaximumValue,i.Unit,i.Instructions})}).ToListAsync(ct)));[HttpGet("templates/{id:guid}")]public async Task<IActionResult>Template(Guid id,CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.MaintenanceChecklistTemplates.AsNoTracking().Where(x=>x.Id==id).Select(x=>new{x.Id,x.Name,x.AssetType,x.WorkType,x.Description,x.IsActive,Items=x.Items.OrderBy(i=>i.Sequence)}).FirstOrDefaultAsync(ct)));
[HttpPost("templates"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceChecklists),Idempotent]public async Task<IActionResult>Create(TemplateInput r,CancellationToken ct){var x=new MaintenanceChecklistTemplate{Id=Guid.NewGuid(),Name=r.Name,AssetType=r.AssetType,WorkType=r.WorkType,Description=r.Description,Items=r.Items.Select(i=>new MaintenanceChecklistTemplateItem{Id=Guid.NewGuid(),Sequence=i.Sequence,ItemText=i.ItemText,ItemType=i.ItemType,IsRequired=i.IsRequired,ExpectedValue=i.ExpectedValue,MinimumValue=i.MinimumValue,MaximumValue=i.MaximumValue,Unit=i.Unit,Instructions=i.Instructions}).ToList()};db.Add(x);await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Name}));}[HttpPut("templates/{id:guid}"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceChecklists)]public async Task<IActionResult>Update(Guid id,TemplateInput r,CancellationToken ct){var x=await db.MaintenanceChecklistTemplates.FindAsync([id],ct);if(x is null)return NotFound();x.Name=r.Name;x.AssetType=r.AssetType;x.WorkType=r.WorkType;x.Description=r.Description;await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id}));}[HttpPost("templates/{id:guid}/activate"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceChecklists)]public Task<IActionResult>Activate(Guid id,CancellationToken ct)=>Toggle(id,true,ct);[HttpPost("templates/{id:guid}/deactivate"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceChecklists)]public Task<IActionResult>Deactivate(Guid id,CancellationToken ct)=>Toggle(id,false,ct);
[HttpGet("work-order/{workOrderId:guid}")]public async Task<IActionResult>Results(Guid workOrderId,CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.MaintenanceChecklistResults.AsNoTracking().Where(x=>x.MaintenanceWorkOrderId==workOrderId).OrderBy(x=>x.TemplateItem.Sequence).Select(x=>new{x.Id,x.TemplateItemId,x.TemplateItem.Sequence,x.TemplateItem.ItemText,x.TemplateItem.ItemType,x.TemplateItem.IsRequired,x.IsCompleted,x.PassFail,x.TextValue,x.NumericValue,x.Unit,x.Notes,x.CompletedAt,x.CompletedByName,OutOfTolerance=x.NumericValue.HasValue&&((x.TemplateItem.MinimumValue.HasValue&&x.NumericValue<x.TemplateItem.MinimumValue)||(x.TemplateItem.MaximumValue.HasValue&&x.NumericValue>x.TemplateItem.MaximumValue))}).ToListAsync(ct)));[HttpPut("work-order/{workOrderId:guid}/results"),Authorize(Policy=AuthorizationPolicies.CanManageMaintenanceChecklists),Idempotent]public async Task<IActionResult>UpdateResults(Guid workOrderId,List<ResultInput> rows,CancellationToken ct){var wo=await db.MaintenanceWorkOrders.FindAsync([workOrderId],ct);if(wo is null)return NotFound(ApiResponse<object>.Fail("Bakım iş emri bulunamadı."));if(wo.Status is "Completed" or "Verified" or "Closed" or "Cancelled")return Conflict(ApiResponse<object>.Fail("Tamamlanmış bakım iş emri değiştirilemez."));foreach(var r in rows){var x=await db.MaintenanceChecklistResults.FirstOrDefaultAsync(x=>x.MaintenanceWorkOrderId==workOrderId&&x.TemplateItemId==r.TemplateItemId,ct);if(x is null){x=new MaintenanceChecklistResult{Id=Guid.NewGuid(),MaintenanceWorkOrderId=workOrderId,TemplateItemId=r.TemplateItemId};db.Add(x);}x.IsCompleted=r.IsCompleted;x.PassFail=r.PassFail;x.TextValue=r.TextValue;x.NumericValue=r.NumericValue;x.Unit=r.Unit;x.Notes=r.Notes;x.CompletedAt=r.IsCompleted?DateTime.UtcNow:null;x.CompletedByUserId=r.IsCompleted?user.UserId:null;x.CompletedByName=r.IsCompleted?user.UserName:null;}await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{Updated=rows.Count}));}async Task<IActionResult>Toggle(Guid id,bool active,CancellationToken ct){var x=await db.MaintenanceChecklistTemplates.FindAsync([id],ct);if(x is null)return NotFound();x.IsActive=active;await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.IsActive}));}}

[ApiController,ApiVersion("1.0"),Route("api/v{version:apiVersion}/maintenance-parts"),Authorize(Policy=AuthorizationPolicies.CanUseMaintenanceParts)]public class MaintenancePartsController(ApplicationDbContext db,ICurrentUserService user):ControllerBase{
[HttpGet("work-order/{workOrderId:guid}")]public async Task<IActionResult>List(Guid workOrderId,CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.MaintenancePartUsages.AsNoTracking().Where(x=>x.MaintenanceWorkOrderId==workOrderId).Select(x=>new{x.Id,x.StockItemId,StockItem=x.StockItem.Name,x.MaterialId,x.Quantity,x.Unit,x.UnitCost,x.Currency,x.TotalCost,x.Status,x.StockMovementId,x.PostedAt,x.IsReversed,x.ReversalStockMovementId,x.ReversedAt,x.ReversalReason,x.Notes}).ToListAsync(ct)));[HttpPost("work-order/{workOrderId:guid}"),Idempotent]public async Task<IActionResult>Create(Guid workOrderId,PartInput r,CancellationToken ct){if(r.Quantity<=0)return BadRequest(ApiResponse<object>.Fail("Parça miktarı sıfırdan büyük olmalıdır."));var stock=await db.StockItems.FindAsync([r.StockItemId],ct);if(stock is null)return NotFound(ApiResponse<object>.Fail("Stok kalemi bulunamadı."));if(stock.Unit!=r.Unit)return Conflict(ApiResponse<object>.Fail("Bakım parçası birimi stok birimiyle eşleşmiyor."));if(stock.MaterialId.HasValue&&stock.Category.Contains("Hammadde",StringComparison.OrdinalIgnoreCase))return Conflict(ApiResponse<object>.Fail("Kimyasal hammadde bakım parçası olarak kullanılamaz."));var x=new MaintenancePartUsage{Id=Guid.NewGuid(),MaintenanceWorkOrderId=workOrderId,StockItemId=r.StockItemId,MaterialId=stock.MaterialId,Quantity=r.Quantity,Unit=r.Unit,UnitCost=r.UnitCost??stock.LastPurchasePrice,Currency=r.Currency??stock.Currency,TotalCost=r.Quantity*(r.UnitCost??stock.LastPurchasePrice??0),Notes=r.Notes};db.Add(x);await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status,x.TotalCost}));}[HttpPut("{id:guid}")]public async Task<IActionResult>Update(Guid id,PartInput r,CancellationToken ct){var x=await db.MaintenancePartUsages.FindAsync([id],ct);if(x is null)return NotFound();if(x.Status!="Draft")return Conflict(ApiResponse<object>.Fail("Yalnız taslak parça kullanımı değiştirilebilir."));x.Quantity=r.Quantity;x.UnitCost=r.UnitCost;x.TotalCost=r.Quantity*(r.UnitCost??0);x.Notes=r.Notes;await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));}
[HttpPost("{id:guid}/post"),Idempotent]public async Task<IActionResult>Post(Guid id,CancellationToken ct){await using var tx=await db.Database.BeginTransactionAsync(ct);var x=await db.MaintenancePartUsages.Include(x=>x.StockItem).FirstOrDefaultAsync(x=>x.Id==id,ct);if(x is null)return NotFound();if(x.Status=="Posted")return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status},"Bu parça kullanımı daha önce post edilmiş."));if(x.Status!="Draft")return Conflict(ApiResponse<object>.Fail("Parça kullanımı post edilemez."));if(x.StockItem.Unit!=x.Unit)return Conflict(ApiResponse<object>.Fail("Bakım parçası birimi stok birimiyle eşleşmiyor."));if(x.StockItem.CurrentQuantity<x.Quantity)return Conflict(ApiResponse<object>.Fail("Bakım parçası stoğu yetersiz."));x.StockItem.CurrentQuantity-=x.Quantity;var m=new StockMovement{Id=Guid.NewGuid(),StockItemId=x.StockItemId,MovementType="MaintenancePartConsumption",Quantity=-x.Quantity,UnitPrice=x.UnitCost,MovementDate=DateTime.UtcNow,SourceType="MaintenancePartUsage",SourceDocumentNo=x.Id.ToString(),Note=x.Notes};db.Add(m);x.StockMovementId=m.Id;x.Status="Posted";x.PostedAt=DateTime.UtcNow;x.PostedBy=user.UserId;await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status,x.StockMovementId}));}[HttpPost("{id:guid}/reverse"),Idempotent]public async Task<IActionResult>Reverse(Guid id,ReasonInput r,CancellationToken ct){if(string.IsNullOrWhiteSpace(r.Reason))return BadRequest(ApiResponse<object>.Fail("Geri alma gerekçesi zorunludur."));await using var tx=await db.Database.BeginTransactionAsync(ct);var x=await db.MaintenancePartUsages.Include(x=>x.StockItem).FirstOrDefaultAsync(x=>x.Id==id,ct);if(x is null)return NotFound();if(x.IsReversed)return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status},"Bu parça kullanımı daha önce geri alınmış."));if(x.Status!="Posted")return Conflict(ApiResponse<object>.Fail("Yalnız post edilmiş parça geri alınabilir."));x.StockItem.CurrentQuantity+=x.Quantity;var m=new StockMovement{Id=Guid.NewGuid(),StockItemId=x.StockItemId,MovementType="MaintenancePartReversal",Quantity=x.Quantity,UnitPrice=x.UnitCost,MovementDate=DateTime.UtcNow,SourceType="MaintenancePartUsageReversal",SourceDocumentNo=x.Id.ToString(),Note=r.Reason};db.Add(m);x.IsReversed=true;x.Status="Reversed";x.ReversalStockMovementId=m.Id;x.ReversedAt=DateTime.UtcNow;x.ReversedBy=user.UserId;x.ReversalReason=r.Reason;await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status,x.ReversalStockMovementId}));}[HttpPost("{id:guid}/cancel"),Idempotent]public async Task<IActionResult>Cancel(Guid id,CancellationToken ct){var x=await db.MaintenancePartUsages.FindAsync([id],ct);if(x is null)return NotFound();if(x.Status!="Draft")return Conflict(ApiResponse<object>.Fail("Yalnız taslak parça kullanımı iptal edilebilir."));x.Status="Cancelled";await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));}}

[ApiController,ApiVersion("1.0"),Route("api/v{version:apiVersion}/maintenance"),Authorize(Policy=AuthorizationPolicies.CanViewMaintenance)]public class MaintenanceDashboardController(ApplicationDbContext db):ControllerBase{[HttpGet("dashboard")]public async Task<IActionResult>Dashboard(CancellationToken ct){var now=DateTime.UtcNow;var start=new DateTime(now.Year,now.Month,1);var completed=await db.MaintenanceWorkOrders.AsNoTracking().Where(x=>x.ActualEnd>=start&&x.ActualStart!=null).ToListAsync(ct);var failures=await db.MaintenanceRequests.AsNoTracking().Where(x=>x.RequestType=="Breakdown").GroupBy(x=>new{x.MaintenanceAssetId,x.MaintenanceAsset.AssetName}).Select(g=>new{g.Key.MaintenanceAssetId,g.Key.AssetName,Count=g.Count()}).OrderByDescending(x=>x.Count).Take(5).ToListAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{OpenRequestCount=await db.MaintenanceRequests.CountAsync(x=>x.Status!="Closed"&&x.Status!="Cancelled",ct),CriticalOpenRequestCount=await db.MaintenanceRequests.CountAsync(x=>x.Priority=="Critical"&&x.Status!="Closed"&&x.Status!="Cancelled",ct),InProgressWorkOrderCount=await db.MaintenanceWorkOrders.CountAsync(x=>x.Status=="InProgress",ct),WaitingForPartCount=await db.MaintenanceWorkOrders.CountAsync(x=>x.Status=="WaitingForPart",ct),OverduePreventivePlanCount=await db.PreventiveMaintenancePlans.CountAsync(x=>x.IsActive&&x.NextDueDate<now.Date,ct),DueIn7DaysCount=await db.PreventiveMaintenancePlans.CountAsync(x=>x.IsActive&&x.NextDueDate>=now.Date&&x.NextDueDate<=now.Date.AddDays(7),ct),DueIn30DaysCount=await db.PreventiveMaintenancePlans.CountAsync(x=>x.IsActive&&x.NextDueDate>=now.Date&&x.NextDueDate<=now.Date.AddDays(30),ct),DowntimeMinutesThisMonth=completed.Sum(x=>x.DowntimeMinutes),CompletedWorkOrdersThisMonth=completed.Count,AverageRepairTimeMinutes=completed.Count==0?0:completed.Average(x=>(x.ActualEnd!.Value-x.ActualStart!.Value).TotalMinutes),RepeatFailureAssetCount=failures.Count(x=>x.Count>1),TopFailureAssets=failures,RecentRequests=await db.MaintenanceRequests.AsNoTracking().OrderByDescending(x=>x.ReportedAt).Take(5).Select(x=>new{x.RequestNumber,x.Title,x.Priority,x.Status,Asset=x.MaintenanceAsset.AssetName}).ToListAsync(ct),UpcomingPreventiveMaintenance=await db.PreventiveMaintenancePlans.AsNoTracking().Where(x=>x.IsActive&&x.NextDueDate>=now.Date).OrderBy(x=>x.NextDueDate).Take(5).Select(x=>new{x.PlanCode,x.Name,x.NextDueDate,Asset=x.MaintenanceAsset.AssetName}).ToListAsync(ct),LowStockSpareParts=await db.StockItems.AsNoTracking().Where(x=>x.IsActive&&x.CurrentQuantity<=x.CriticalQuantity&&(x.Category.Contains("Yedek")||x.Category.Contains("Spare"))).Select(x=>new{x.Id,x.Code,x.Name,x.CurrentQuantity,x.CriticalQuantity,x.Unit}).ToListAsync(ct),Warnings=new[]{"MTBF çalışma saati verisi olmadan hesaplanmamıştır."}}));}}
public record TemplateInput(string Name,string? AssetType,string? WorkType,string? Description,List<TemplateItemInput> Items);public record TemplateItemInput(int Sequence,string ItemText,string ItemType,bool IsRequired,string? ExpectedValue,decimal? MinimumValue,decimal? MaximumValue,string? Unit,string? Instructions);public record ResultInput(Guid TemplateItemId,bool IsCompleted,bool? PassFail,string? TextValue,decimal? NumericValue,string? Unit,string? Notes);public record PartInput(Guid StockItemId,decimal Quantity,string Unit,decimal? UnitCost,string? Currency,string? Notes);
